field.expression:
@salida_trunca:= (case when @difsalida  >= '00:30:00' && @difsalida <= '00:55:00' 
                      then CONCAT(substring(@horasal, 1, 2) ,':30:00') 
              when @difsalida < '00:30:00' then CONCAT(substring(@horasal, 1, 2) ,':00:00') 
            when @difsalida > '00:55:00' then CONCAT(substring(@horasal, 1, 2) + 1 ,':00:00') 
              end)

(case when !isnull(h3) then ( 
                 ADDTIME( TIMEDIFF( @salida_trunca , h3 ) ,  TIMEDIFF( h2, @entrada_trunca) )
                    ) else   
                      TIMEDIFF( @salida_trunca, @entrada_trunca ) 
                    end)
